API_name: nchu_course_get_weekly_content
Description:
{
  "description": "Get weekly course content for a specific course. JSON string containing weekly course content (每週授課內容)",
  "required_parameters": [
    {
      "name": "course_id",
      "type": "STRING",
      "description": "Course ID (選課號碼)"
    }
  ],
  "optional_parameters": [
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

